@app.post("/auth/password-reset/request")
def request_password_reset():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()

    if not email:
        return jsonify({"error": "email is required"}), 400

    token = secrets.token_urlsafe(32)
    now = datetime.now(timezone.utc)
    ttl = timedelta(minutes=app.config["RESET_TOKEN_TTL_MINUTES"])
    expires_at = now + ttl

    reset_rec = PasswordResetToken(email=email, token=token, created_at=now, expires_at=expires_at)
    db.session.add(reset_rec)
    db.session.commit()

    if app.config["RESET_BASE_URL"]:
        reset_link = f"{app.config['RESET_BASE_URL']}/reset-password?token={token}"
    else:
        reset_link = url_for("reset_password_stub", token=token, _external=True)

    send_reset_email(email, reset_link)

    return jsonify({"ok": True}), 200


